// Safe command executor
class SafeCommandExecutor(timeoutSeconds: Int = 30) {

  def execute(request: CommandRequest): Either[String, CommandResult] = {
    for {
      command    <- validateCommand(request.command)
      arguments  <- validateArguments(command, request.arguments)
      result     <- runCommand(command, arguments)
    } yield result
  }

  private def validateCommand(name: String): Either[String, AllowedCommand] = {
    CommandRegistry.get(name) match {
      case Some(cmd) => Right(cmd)
      case None =>
        Left(s"Command '$name' is not in the allowed list. Available: ${CommandRegistry.listAvailable.mkString(", ")}")
    }
  }

  private def validateArguments(command: AllowedCommand, userArgs: List[String]): Either[String, List[String] = {
    if (userArgs.length > command.maxUserArgs) {
      Left(s"Too many arguments. Command '${command.name}' allows max ${command.maxUserArgs} arguments.")
    } else {
      val invalidArgs = userArgs.filterNot(command.argumentValidator)
      if (invalidArgs.nonEmpty) {
        Left(s"Invalid arguments detected: ${invalidArgs.mkString(", ")}. Arguments contain disallowed characters or patterns.")
      } else {
        Right(command.fixedArgs ++ userArgs)
      }
    }
  }

  // SAFE: Uses Process with a sequence of strings - NO shell interpolation
  private def runCommand(command: AllowedCommand, arguments: List[String]): Either[String, CommandResult] = {
    val fullCommand: Seq[String] = command.executable +: arguments

    println(s"[AUDIT] Executing: ${fullCommand.mkString(" ")}")

    val stdoutBuilder = new StringBuilder
    val stderrBuilder = new StringBuilder

    val processLogger = ProcessLogger(
      line => stdoutBuilder.append(line).append("\n"),
      line => stderrBuilder.append(line).append("\n")
    )

    Try {
      // SAFE: Process(Seq[String]) does NOT invoke a shell
      // Each element is passed as a separate argument to execvp
      // This prevents command injection entirely
      val process = Process(fullCommand)
      val exitCode = process.!(processLogger)

      CommandResult(
        exitCode = exitCode,
        stdout = stdoutBuilder.toString().trim,
        stderr = stderrBuilder.toString().trim,
        success = exitCode == 0
      )
    } match {
      case Success(result) => Right(result)
      case Failure(ex) => Left(s"Command execution failed: ${ex.getMessage}")
    }
  }
}

// Simple HTTP-like API service
class DevOpsAutomationService {
  private val executor = new SafeCommandExecutor()

  def handleRequest(commandName: String, arguments: List[String]): String = {
    val sanitizedCommandName = commandName.replaceAll("[^a-zA-Z0-9\\-]", "")

    val request = CommandRequest(
      command = sanitizedCommandName,
      arguments = arguments
    )

    executor.execute(request) match {
      case Right(result) =>
        s"""
           |=== Command Result ===
           |Command: $sanitizedCommandName
           |Exit Code: ${result.exitCode}
           |Success: ${result.success}
           |--- STDOUT ---
           |${result.stdout}
           |--- STDERR ---
           |${result.stderr}
           |==================
         """.stripMargin

      case Left(error) =>
        s"""
           |=== Error ===
           |$error
           |=============
         """.stripMargin
    }
  }

  def listCommands(): String = {
    s"Available commands: ${CommandRegistry.listAvailable.mkString(", ")}"
  }
}

